        <Grid item xs={12} md={7}>
          <Card sx={{ height: '100%' }}>
            <CardContent sx={{ p: 4 }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
                <Typography variant="h5" sx={{ fontWeight: 700 }}>
                  Compliance & Verification Documents
                </Typography>
                <Button
                  variant="contained"
                  component="label"
                  size="small"
                  startIcon={<CloudUploadIcon />}
                  sx={{ fontWeight: 600 }}
                >
                  Upload File
                  <input type="file" hidden onChange={handleFileUpload} />
                </Button>
              </Box>

              <Divider sx={{ mb: 2.5 }} />

              <List sx={{ p: 0 }}>
                {(!user?.documents || user.documents.length === 0) ? (
                  <Paper sx={{ p: 3, textAlign: 'center', bgcolor: '#F8FAFC' }}>
                    <Typography color="text.secondary" variant="body2">No files uploaded yet.</Typography>
                  </Paper>
                ) : (
                  user.documents.map((doc, idx) => (
                    <Paper key={doc.id || idx} variant="outlined" sx={{ mb: 2, borderRadius: 2 }}>
                      <ListItem sx={{ py: 1.8 }}>
                        <ListItemIcon sx={{ minWidth: 40 }}>
                          <InsertDriveFileIcon color="primary" />
                        </ListItemIcon>
                        <ListItemText
                          primary={doc.name}
                          secondary={`Uploaded on: ${doc.date}`}
                          primaryTypographyProps={{ fontWeight: 600, fontSize: '0.875rem' }}
                        />
                        <Typography variant="caption" color="text.secondary" sx={{ fontWeight: 600 }}>
                          {doc.size}
                        </Typography>
                      </ListItem>
                    </Paper>
                  ))
                )}
              </List>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      {/* Edit Profile Modal */}
      <Dialog open={openEditModal} onClose={() => setOpenEditModal(false)} maxWidth="xs" fullWidth>
        <DialogTitle sx={{ fontWeight: 700 }}>Edit Corporate Details</DialogTitle>
        <Divider />
        <form onSubmit={handleUpdate}>
          <DialogContent sx={{ p: 3 }}>
            <TextField
              fullWidth
              label="Corporate Entity Business Name"
              value={businessName}
              onChange={(e) => setBusinessName(e.target.value)}
              sx={{ mb: 2.5 }}
              required
            />
            <TextField
              fullWidth
              label="Contact Liaison Name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              sx={{ mb: 2.5 }}
              required
            />
            <TextField
              fullWidth
              label="Liaison Email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              sx={{ mb: 2.5 }}
              required
            />
            <TextField
              fullWidth
              label="Liaison Phone"
              value={phone}
              onChange={(e) => setPhone(e.target.value)}
              required
            />
          </DialogContent>
          <Divider />
          <DialogActions sx={{ p: 2.5 }}>
            <Button onClick={() => setOpenEditModal(false)} variant="outlined" color="inherit">
              Cancel
            </Button>
            <Button type="submit" variant="contained" color="primary" sx={{ fontWeight: 600 }}>
              Save Changes
            </Button>
          </DialogActions>
        </form>
      </Dialog>

      {/* Success Toast */}
      <NotificationToast
        open={toastOpen}
        message={toastMessage}
        onClose={() => setToastOpen(false)}
      />
    </Box>
  );
};

