import React from 'react';
import { Grid, Typography, Box, Card, CardContent, Button } from '@mui/material';
import StatCard from '../../components/dashboard/StatCard';
import BarReportChart from '../../components/charts/BarReportChart';
import PieReportChart from '../../components/charts/PieReportChart';
import CustomTable from '../../components/tables/CustomTable';
import StatusBadge from '../../components/common/StatusBadge';
import { useAuth } from '../../context/AuthContext';
import CorporateFareIcon from '@mui/icons-material/CorporateFare';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import WarningIcon from '@mui/icons-material/Warning';
import MonetizationOnIcon from '@mui/icons-material/MonetizationOn';
import AssignmentLateIcon from '@mui/icons-material/AssignmentLate';
import SupportIcon from '@mui/icons-material/Support';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import { useNavigate } from 'react-router-dom';

const AdminDashboard = () => {
  const { warehouses, payments, tickets } = useAuth();
  const navigate = useNavigate();

  // Stats calculation
  const totalWarehouses = warehouses.length;
  const occupiedCount = warehouses.filter((w) => w.status === 'Booked').length;
  const vacantCount = warehouses.filter((w) => w.status === 'Available').length;
  const maintenanceCount = warehouses.filter((w) => w.status === 'Maintenance').length;

  const totalRevenue = payments
    .filter((p) => p.status === 'Paid')
    .reduce((sum, p) => sum + p.amount, 0);

  const pendingAmount = payments
    .filter((p) => p.status === 'Pending' || p.status === 'Overdue')
    .reduce((sum, p) => sum + p.amount, 0);

  const openTicketsCount = tickets.filter(
    (t) => t.status === 'Open' || t.status === 'In Progress'
  ).length;

  // Pie Chart Occupancy Data
  const occupancyData = [
    { name: 'Occupied (Booked)', value: occupiedCount },
    { name: 'Vacant (Available)', value: vacantCount },
    { name: 'Maintenance', value: maintenanceCount }
  ];

  // Revenue chart data grouped by month
  const monthlyRevenueData = [
    { name: 'Jan 2026', value: 12000 },
    { name: 'Feb 2026', value: 14500 },
    { name: 'Mar 2026', value: 13000 },
    { name: 'Apr 2026', value: 16000 },
    { name: 'May 2026', value: 15500 },
    { name: 'Jun 2026', value: totalRevenue > 0 ? totalRevenue : 10000 }
  ];

  // Table Headers
  const payHeaders = [
    { id: 'businessName', label: 'Tenant Company' },
    { id: 'month', label: 'Billing Period' },
    { id: 'amount', label: 'Amount', render: (row) => `$${row.amount.toLocaleString()}` },
    { id: 'status', label: 'Status', render: (row) => <StatusBadge status={row.status} /> }
  ];

  const ticketHeaders = [
    { id: 'id', label: 'Ticket ID' },
    { id: 'businessName', label: 'Company' },
    { id: 'category', label: 'Category' },
    { id: 'priority', label: 'Priority', render: (row) => <StatusBadge status={row.priority} /> },
    { id: 'status', label: 'Status', render: (row) => <StatusBadge status={row.status} /> }
  ];

  return (
    <Box>
      <Box sx={{ mb: 4, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Box>
          <Typography variant="h4" sx={{ fontWeight: 800 }}>Admin Dashboard</Typography>
          <Typography variant="body2" color="text.secondary">
            Global warehouse logistics metrics, revenue summaries, and ticket resolution logs.
          </Typography>
        </Box>
        <Button
          variant="contained"
          color="primary"
          endIcon={<ArrowForwardIcon />}
          onClick={() => navigate('/admin/reports')}
        >
          View Full Reports
        </Button>
      </Box>

      {/* Statistics Row */}
      <Grid container spacing={3} sx={{ mb: 4 }}>
        <Grid item xs={12} sm={6} md={4} lg={2}>
          <StatCard
            title="Total Units"
            value={totalWarehouses}
            icon={<CorporateFareIcon />}
            color="#1E3A8A"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={4} lg={2}>
          <StatCard
            title="Occupied"
            value={occupiedCount}
            icon={<CheckCircleIcon />}
            color="#10B981"
            subtitle={`${((occupiedCount / totalWarehouses) * 100).toFixed(0)}% Occupancy`}
          />
        </Grid>
        <Grid item xs={12} sm={6} md={4} lg={2}>
          <StatCard
            title="Vacant"
            value={vacantCount}
            icon={<WarningIcon />}
            color="#F59E0B"
            subtitle={`${((vacantCount / totalWarehouses) * 100).toFixed(0)}% Available`}
          />
        </Grid>
        <Grid item xs={12} sm={6} md={4} lg={2}>
          <StatCard
            title="Revenue Collected"
            value={`$${totalRevenue.toLocaleString()}`}
            icon={<MonetizationOnIcon />}
            color="#10B981"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={4} lg={2}>
          <StatCard
            title="Pending Dues"
            value={`$${pendingAmount.toLocaleString()}`}
            icon={<AssignmentLateIcon />}
            color="#EF4444"
          />
        </Grid>
        <Grid item xs={12} sm={6} md={4} lg={2}>
          <StatCard
            title="Open Tickets"
            value={openTicketsCount}
            icon={<SupportIcon />}
            color="#2563EB"
            subtitle="Require response"
          />
        </Grid>
      </Grid>

      {/* Visual Analytics Row */}
      <Grid container spacing={3} sx={{ mb: 4 }}>
        <Grid item xs={12} md={7}>
          <Card>
            <CardContent>
              <Typography variant="h5" sx={{ mb: 3, fontWeight: 700 }}>
                Revenue Performance (Monthly)
              </Typography>
              <BarReportChart data={monthlyRevenueData} />
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} md={5}>
          <Card sx={{ height: '100%' }}>
            <CardContent>
              <Typography variant="h5" sx={{ mb: 3, fontWeight: 700 }}>
                Occupancy Breakdown
              </Typography>
              <PieReportChart data={occupancyData} />
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      {/* Recent Records Row */}
      <Grid container spacing={3}>
        {/* Recent Payments */}
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2.5 }}>
                <Typography variant="h5" sx={{ fontWeight: 700 }}>
                  Recent Rents Received
                </Typography>
                <Button size="small" onClick={() => navigate('/admin/payments')}>
                  Manage Payments
                </Button>
              </Box>
              <CustomTable
                headers={payHeaders}
                data={payments.slice(0, 4)}
                emptyMessage="No recent payments recorded."
                defaultRowsPerPage={4}
              />
            </CardContent>
          </Card>
        </Grid>

        {/* Recent Tickets */}
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2.5 }}>
                <Typography variant="h5" sx={{ fontWeight: 700 }}>
                  Active Support Tickets
                </Typography>
                <Button size="small" onClick={() => navigate('/admin/tickets')}>
                  Monitor Tickets
                </Button>
              </Box>
              <CustomTable
                headers={ticketHeaders}
                data={tickets.slice(0, 4)}
                emptyMessage="No active tickets."
                defaultRowsPerPage={4}
              />
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

export default AdminDashboard;

import React, { useState } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  Button,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  MenuItem,
  FormControl,
  InputLabel,
  Select,
  Grid,
  Divider,
  Alert
} from '@mui/material';
import CustomTable from '../../components/tables/CustomTable';
import StatusBadge from '../../components/common/StatusBadge';
import NotificationToast from '../../components/common/NotificationToast';
import { useAuth } from '../../context/AuthContext';
import AddIcon from '@mui/icons-material/Add';
import EditIcon from '@mui/icons-material/Edit';

const WarehouseManagement = () => {
  const { warehouses, addWarehouse, updateWarehouse } = useAuth();

  // Modal State
  const [openModal, setOpenModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedWhId, setSelectedWhId] = useState(null);

  // Form Fields State
  const [number, setNumber] = useState('');
  const [size, setSize] = useState('');
  const [block, setBlock] = useState('Block A');
  const [floor, setFloor] = useState('Ground Floor');
  const [rent, setRent] = useState('');
  const [status, setStatus] = useState('Available');
  const [formError, setFormError] = useState('');

  // Toast notifications State
  const [toastOpen, setToastOpen] = useState(false);
  const [toastMessage, setToastMessage] = useState('');

  const handleOpenAdd = () => {
    setEditMode(false);
    setSelectedWhId(null);
    setNumber('');
    setSize('');
    setBlock('Block A');
    setFloor('Ground Floor');
    setRent('');
    setStatus('Available');
    setFormError('');
    setOpenModal(true);
  };

  const handleOpenEdit = (wh) => {
    setEditMode(true);
    setSelectedWhId(wh.id);
    setNumber(wh.number);
    setSize(wh.size);
    setBlock(wh.block);
    setFloor(wh.floor);
    setRent(wh.rent.toString());
    setStatus(wh.status);
    setFormError('');
    setOpenModal(true);
  };

  const handleFormSubmit = (e) => {
    e.preventDefault();
    setFormError('');

    if (!number || !size || !rent) {
      setFormError('Please fill in all required fields.');
      return;
    }
    if (isNaN(rent) || parseFloat(rent) <= 0) {
      setFormError('Please enter a valid positive rent amount.');
      return;
    }

    const payload = {
      number,
      size,
      block,
      floor,
      rent: parseFloat(rent),
      status
    };

    if (editMode) {
      updateWarehouse(selectedWhId, payload);
      setToastMessage(`Warehouse ${number} updated successfully!`);
    } else {
      addWarehouse(payload);
      setToastMessage(`Warehouse ${number} created successfully!`);
    }

    setOpenModal(false);
    setToastOpen(true);
  };

  const headers = [
    { id: 'number', label: 'Warehouse Number' },
    { id: 'size', label: 'Size (sq ft)' },
    { id: 'block', label: 'Block' },
    { id: 'floor', label: 'Floor Level' },
    { id: 'rent', label: 'Monthly Rent', render: (row) => `$${row.rent.toLocaleString()}` },
    { id: 'status', label: 'Status', render: (row) => <StatusBadge status={row.status} /> },
    {
      id: 'actions',
      label: 'Actions',
      align: 'right',
      render: (row) => (
        <IconButton size="small" color="secondary" onClick={() => handleOpenEdit(row)}>
          <EditIcon fontSize="small" />
        </IconButton>
      ),
    },
  ];

  return (
    <Box>
      <Box sx={{ mb: 4, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Box>
          <Typography variant="h4" sx={{ fontWeight: 800 }}>Warehouse Management</Typography>
          <Typography variant="body2" color="text.secondary">
            Manage your physical assets, record floor mappings, and set lease prices.
          </Typography>
        </Box>
        <Button
          variant="contained"
          color="primary"
          startIcon={<AddIcon />}
          onClick={handleOpenAdd}
          sx={{ fontWeight: 600 }}
        >
          Add Warehouse
        </Button>
      </Box>

      {/* Warehouses Table */}
      <Card>
        <CardContent sx={{ p: 4 }}>
          <Typography variant="h5" sx={{ fontWeight: 700, mb: 3 }}>
            Warehouse Fleet Registry
          </Typography>
          <CustomTable
            headers={headers}
            data={warehouses}
            emptyMessage="No warehouses recorded in the system."
            defaultRowsPerPage={5}
          />
        </CardContent>
      </Card>

      {/* Add / Edit Dialog Modal */}
      <Dialog open={openModal} onClose={() => setOpenModal(false)} maxWidth="sm" fullWidth>
        <DialogTitle sx={{ fontWeight: 700 }}>
          {editMode ? `Edit Warehouse - ${number}` : 'Add New Warehouse'}
        </DialogTitle>
        <Divider />
        <form onSubmit={handleFormSubmit}>
          <DialogContent sx={{ p: 3 }}>
            {formError && (
              <Alert severity="error" sx={{ mb: 2 }}>
                {formError}
              </Alert>
            )}

            <Grid container spacing={2}>
              <Grid item xs={12} sm={6}>
                <TextField
                  fullWidth
                  label="Warehouse Number"
                  required
                  placeholder="e.g. WH-104"
                  value={number}
                  onChange={(e) => setNumber(e.target.value)}
                  disabled={editMode} // lock number on edit
                />
              </Grid>

              <Grid item xs={12} sm={6}>
                <TextField
                  fullWidth
                  label="Dimensions (e.g. 15,000 sq ft)"
                  required
                  placeholder="e.g. 12,500 sq ft"
                  value={size}
                  onChange={(e) => setSize(e.target.value)}
                />
              </Grid>

              <Grid item xs={12} sm={6}>
                <FormControl fullWidth required>
                  <InputLabel id="block-select-label">Block Section</InputLabel>
                  <Select
                    labelId="block-select-label"
                    value={block}
                    label="Block Section"
                    onChange={(e) => setBlock(e.target.value)}
                  >
                    <MenuItem value="Block A">Block A</MenuItem>
                    <MenuItem value="Block B">Block B</MenuItem>
                    <MenuItem value="Block C">Block C</MenuItem>
                    <MenuItem value="Block D">Block D</MenuItem>
                  </Select>
                </FormControl>
              </Grid>

              <Grid item xs={12} sm={6}>
                <FormControl fullWidth required>
                  <InputLabel id="floor-select-label">Floor Location</InputLabel>
                  <Select
                    labelId="floor-select-label"
                    value={floor}
                    label="Floor Location"
                    onChange={(e) => setFloor(e.target.value)}
                  >
                    <MenuItem value="Ground Floor">Ground Floor</MenuItem>
                    <MenuItem value="1st Floor">1st Floor</MenuItem>
                    <MenuItem value="2nd Floor">2nd Floor</MenuItem>
                  </Select>
                </FormControl>
              </Grid>

              <Grid item xs={12} sm={6}>
                <TextField
                  fullWidth
                  label="Monthly Rent Charge ($)"
                  required
                  placeholder="e.g. 3500"
                  value={rent}
                  onChange={(e) => setRent(e.target.value)}
                />
              </Grid>

              <Grid item xs={12} sm={6}>
                <FormControl fullWidth required>
                  <InputLabel id="status-select-label">Unit Status</InputLabel>
                  <Select
                    labelId="status-select-label"
                    value={status}
                    label="Unit Status"
                    onChange={(e) => setStatus(e.target.value)}
                  >
                    <MenuItem value="Available">Available</MenuItem>
                    <MenuItem value="Booked">Booked</MenuItem>
                    <MenuItem value="Maintenance">Maintenance</MenuItem>
                  </Select>
                </FormControl>
              </Grid>
            </Grid>
          </DialogContent>
          <Divider />
          <DialogActions sx={{ p: 2.5 }}>
            <Button onClick={() => setOpenModal(false)} variant="outlined" color="inherit">
              Cancel
            </Button>
            <Button type="submit" variant="contained" color="primary" sx={{ fontWeight: 600 }}>
              {editMode ? 'Save Changes' : 'Register Unit'}
            </Button>
          </DialogActions>
        </form>
      </Dialog>

      {/* Toast Alert */}
      <NotificationToast
        open={toastOpen}
        message={toastMessage}
        onClose={() => setToastOpen(false)}
      />
    </Box>
  );
};

export default WarehouseManagement;

import React, { useState } from 'react';
import {
  Box,
  Typography,
  Card,
