          <CustomTable
            headers={headers}
            data={tickets}
            emptyMessage="No tickets in queue."
            defaultRowsPerPage={10}
          />
        </CardContent>
      </Card>

      {/* Edit Assignment Dialog */}
      <Dialog open={openModal} onClose={() => setOpenModal(false)} maxWidth="sm" fullWidth>
        <DialogTitle sx={{ fontWeight: 700 }}>
