                </FormControl>
              </Grid>

              <Grid item xs={12} sm={6}>
                <FormControl fullWidth required>
                  <InputLabel id="ticket-priority-label">Set Priority</InputLabel>
                  <Select
                    labelId="ticket-priority-label"
                    value={priority}
